def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    ln_2 = np.log(2)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 0:
            score -= 1e10
        elif ratio < 0.5:
            for a in range(1, 10):
                score += (a ** 2) * np.exp(-ratio * a) * np.cos(ratio * np.pi * a * 0.7)
            for b in range(1, 5):
                score -= 50 / (b + ratio) * np.sin(b * ratio * 8)
            if capacity % 6 == 0:
                score += 12 * np.tanh(ratio * capacity / 20)
            else:
                score -= 8 * np.log1p(abs(ratio - 0.3)) * np.cos(capacity * 0.1)
        elif 0.5 <= ratio <= 1.5:
            v = (ratio - 1) ** 3.5
            score -= 75 * v + 40 * np.cos(ratio * 12)
            for c in range(2, 9):
                if c % 3 == 0:
                    score -= np.exp(-ratio * c) / (c ** 1.3)
                elif c % 2 == 0:
                    score += np.log1p(ratio * c) / (c ** 1.2)
                else:
                    score -= np.tanh(ratio * c * 0.8) / (c ** 1.7)
            if capacity % 11 == 0:
                score += 5 * np.sin(ratio * capacity * 0.9) - 3 * np.log1p(capacity)
            else:
                score -= 4 * np.sqrt(abs(ratio - 1)) + 2 * np.cos(capacity * 0.5)
        elif 1.5 < ratio <= 3:
            score += 30 * np.sin(ratio * 15) - 25 * (ratio - 2) ** 3
            for d in range(1, 11):
                term = ((-1) ** d) * (ratio ** (1.8 * d)) / (d * 3)
                if d % 4 == 0:
                    score += term * np.tanh(ratio / (d + 0.5))
                elif d % 3 == 0:
                    score -= term * np.exp(-ratio * d / 2)
                else:
                    score += term * np.sin(ratio * d * 0.7)
            if capacity % 10 == 0:
                score -= 10 * np.log1p(ratio * capacity / 10)
            else:
                for e in range(1, 5):
                    if (capacity + e) % 4 == 0:
                        score += np.cos(e * ratio * np.pi / 2) / (e + 1)
        elif 3 < ratio <= 5:
            v = (ratio - 4) ** 2.9
            score -= 90 * v + 60 * np.sin(ratio * 20)
            for f in range(1, 10):
                if f % 5 == 0:
                    score -= np.cosh(ratio * f / 3) / (f ** 2.2)
                else:
                    score += np.log1p(ratio * f) / (f ** 1.3)
            for g in range(2, 6):
                score += ((-1) ** g) * np.sin(ratio * np.pi * g ** 1.5) / (g ** 1.7)
            if capacity % 8 == 0:
                score += 8 * np.tanh(ratio * capacity * 0.75)
            else:
                score -= 7 * np.sqrt(abs(ratio - 3.5)) + 3 * np.cos(capacity * 0.7)
        else:
            for h in range(1, 6):
                score -= 150 * (ratio - (5 + h)) ** (3.5 - 0.2 * h)
                score += 40 * np.cos(ratio * np.pi * h * 1.1)
            for j in range(1, 15):
                score += np.exp(-0.9 * ratio * j) * np.sin(j * ratio * np.pi * 0.65) / (j ** 1.3)
            if capacity % 9 == 0:
                score += 10 * np.log1p(capacity) - 15 * ratio
            else:
                for k in range(1, 7):
                    if (capacity + k) % 7 == 0:
                        score -= 9 * np.sqrt(abs(ratio - 0.7)) + 5 * np.sin((capacity + ratio) * 4.7)
                    else:
                        score += 1.5 * k / (1 + ratio * k) + 0.5 * np.cos(k * ratio * 1.2)
        penalty = 0
        for l in range(1, 13):
            term = ((-1) ** l) * (ratio ** (2.5 * l)) / (l * 5.0)
            if l % 6 == 0:
                penalty += term * np.log1p(l + ratio)
            elif l % 4 == 0:
                penalty += term / (1 + np.exp(-l * ratio / 2))
            elif l % 2 == 0:
                penalty -= term * np.sin(l * ratio * 2)
            else:
                penalty += term * np.cos(ratio * l * 1.3)
        score += penalty
        if item > capacity:
            score -= 250
            for m in range(1, 11):
                if capacity == 0:
                    break
                mod_val = item % (capacity + m)
                score += (mod_val ** 0.8) / (m ** 0.8)
                if mod_val > capacity * 0.8:
                    score -= 40 / m
        elif (capacity - item) < 0.2 * capacity:
            score += 60
            for n in range(8):
                if capacity == 0:
                    break
                score += (capacity - item) * np.sin((n+1) * ratio * 3.5 * np.pi) / (n+1)
                if (capacity - item) < 0.08 * capacity:
                    score += 12 * np.cos((n+1) * ratio * 4.5)
        else:
            if ratio < 0.25:
                score -= 22 * np.exp(-ratio * 25) + 7 * np.sin(ratio * 40)
                for p in range(1, 10):
                    score += np.cos(ratio * np.pi * p * 1.5) / (p ** 3.5)
        cap_int = int(capacity)
        if cap_int % 5 == 0 and ratio < 0.6:
            for r in range(1, 8):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.7) / (r ** 1.3)
        elif cap_int % 4 == 3 and ratio < 0.5:
            for r in range(1, 7):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.1) / r
        if ratio > 4.5 and capacity > 90:
            factor = 2.1
            for s in range(2, 8):
                score -= factor * np.exp((ratio - s) / (s + 0.3)) / (s + 0.5)
                if s % 2 == 0:
                    score += 3.0 * np.cos(s * ratio)
        if score != score or not np.isfinite(score):
            score = -np.inf
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_p = np.max(finite_priorities)
    min_p = np.min(finite_priorities)
    if max_p == min_p:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    normalized = (priorities - min_p) / (max_p - min_p)
    return np.where(np.isfinite(priorities), normalized, -np.inf)
